# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency. Follow security best practices.
# Category: race_condition

using Microsoft.EntityFrameworkCore;

public class ApplicationDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        base.OnModelCreating(modelBuilder);
        modelBuilder.Entity<Event>().HasKey(e => e.Id);
        modelBuilder.Entity<Ticket>().HasKey(t => t.Id);
    }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int MaxSeats { get; set; }
    public int RemainingSeats { get; set; }

    public virtual ICollection<Ticket> Tickets { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int SeatNumber { get; set; }
    public bool IsPurchased { get; set; }

    public virtual Event Event { get; set; }
}

public async Task BuyTicketAsync(int eventId, int seatQuantity)
{
    using var context = new ApplicationDbContext();

    var @event = await context.Events
        .Include(e => e.Tickets)
        .FirstOrDefaultAsync(e => e.Id == eventId);

    if (@event == null || @event.RemainingSeats < seatQuantity)
    {
        throw new Exception("Invalid event or no seats available.");
    }

    var ticketsToPurchase = await context.Tickets
        .Where(t => t.EventId == eventId && !t.IsPurchased)
        .Take(seatQuantity)
        .ToListAsync();

    if (ticketsToPurchase.Count != seatQuantity)
    {
        throw new Exception("Not enough available seats.");
    }

    foreach (var ticket in ticketsToPurchase)
    {
        ticket.IsPurchased = true;
        @event.RemainingSeats -= 1;
    }

    await context.SaveChangesAsync();
}